// pickCells helper (from Session 4)
function pickCells(n) {
    let all = [0,1,2,3,4,5,6,7,8];
    let picked = [];
    for (let i = 0; i < n; i++) {
        let pos = Math.floor(Math.random() * all.length);
        picked.push(all[pos]);
        all.splice(pos, 1);
    }
    return picked;
}

